def estimate_novelty_adjusted_effect(
    daily_effects: list[float],
    novelty_window_days: int = 7,
) -> float:
    """
    daily_effects: list of per-day relative treatment effect, earliest first.
    Returns mean of the last `novelty_window_days` observations.
    If experiment ran fewer days, returns the full-period mean.
    """
    if len(daily_effects) <= novelty_window_days:
        return sum(daily_effects) / len(daily_effects)
    stable_window = daily_effects[-novelty_window_days:]
    return sum(stable_window) / len(stable_window)

from dataclasses import dataclass, field
from typing import Optional, List
from datetime import datetime

@dataclass
class ExperimentRegistryEntry:
    experiment_id: str
    title: str
    hypothesis: str
    primary_metric: str
    treatment_description: str
    decision: str                     # "ship", "no_ship", "partial_ship", "extend"
    relative_effect: Optional[float]  # None if inconclusive
    p_value: Optional[float]
    subgroup_parity_held: Optional[bool]
    rollout_events: List[dict]        # [{fraction, timestamp, event}]
    shipped_at: Optional[datetime]
    flag_retired_at: Optional[datetime]
    lessons_learned: str = ""

class ExperimentRegistry:
    def __init__(self, store):
        self._store = store  # any key-value store or DB

    def record(self, entry: ExperimentRegistryEntry):
        self._store.put(entry.experiment_id, entry)

    def find_similar(self, hypothesis_keywords: List[str]) -> List[ExperimentRegistryEntry]:
        """Before designing a new experiment, search for prior art."""
        results = []
        for entry in self._store.scan():
            if any(kw.lower() in entry.hypothesis.lower() for kw in hypothesis_keywords):
                results.append(entry)
        return sorted(results, key=lambda e: e.shipped_at or datetime.min, reverse=True)

    def effect_size_reference(self, metric: str) -> dict:
        """Historical distribution of effect sizes for a metric — calibrates new MDE choices."""
        effects = [
            e.relative_effect for e in self._store.scan()
            if e.primary_metric == metric and e.relative_effect is not None
        ]
        if not effects:
            return {}
        return {
            "p25": sorted(effects)[len(effects) // 4],
            "median": sorted(effects)[len(effects) // 2],
            "p75": sorted(effects)[3 * len(effects) // 4],
        }
